import React, { useRef } from "react";
import { motion, useInView } from "framer-motion";
import { projects } from "../data/portfolioData";

export default function Projects() {
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true });

  return (
    <section
      id="projects"
      className="py-40 px-6 bg-[#050505]"
    >
      <div className="max-w-7xl mx-auto">

        {/* Header */}
        <motion.div
          ref={ref}
          initial={{ opacity: 0, y: 40 }}
          animate={isInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.8 }}
          className="mb-32"
        >
          <p className="text-slate-500 uppercase tracking-[0.25em] text-sm mb-4">
            Selected Work
          </p>

          <h2 className="text-white font-bold leading-none tracking-tight text-[clamp(4rem,10vw,8rem)]">
            Projects
          </h2>

          <p className="text-slate-400 max-w-xl mt-8 text-lg">
            AI products, agentic systems, machine learning platforms,
            and intelligent applications designed for real-world impact.
          </p>
        </motion.div>

        {/* Projects */}
        <div className="space-y-40">
          {projects.map((project, index) => (
            <motion.div
              key={project.id}
              initial={{ opacity: 0, y: 60 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.8 }}
              className="group"
            >
              <div
                className={`grid lg:grid-cols-2 gap-16 items-center ${
                  index % 2 === 1 ? "lg:[&>*:first-child]:order-2" : ""
                }`}
              >
                {/* Content */}
                <div>

                  <span className="text-slate-600 text-sm tracking-widest">
                    0{index + 1}
                  </span>

                  <h3 className="text-white text-5xl md:text-6xl font-bold mt-4 mb-8 leading-tight">
                    {project.title}
                  </h3>

                  <p className="text-slate-400 text-lg leading-relaxed mb-8">
                    {project.description}
                  </p>

                  {project.tech && (
                    <div className="flex flex-wrap gap-3 mb-10">
                      {project.tech.map((tech) => (
                        <span
                          key={tech}
                          className="px-4 py-2 rounded-full bg-white/5 text-slate-300 text-sm border border-white/10"
                        >
                          {tech}
                        </span>
                      ))}
                    </div>
                  )}

                  <div className="flex gap-6">
                    {project.github && (
                      <a
                        href={project.github}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="text-white hover:text-[#6c63ff] transition"
                      >
                        GitHub →
                      </a>
                    )}

                    {project.demo && (
                      <a
                        href={project.demo}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="text-white hover:text-[#6c63ff] transition"
                      >
                        Live Demo →
                      </a>
                    )}
                  </div>
                </div>

                {/* Image */}
                <div>
                  <div className="overflow-hidden rounded-[32px] bg-[#0f0f0f] border border-white/5">
                    <img
                      src={project.image}
                      alt={project.title}
                      className="w-full h-[500px] object-cover transition duration-700 group-hover:scale-105"
                    />
                  </div>
                </div>

              </div>
            </motion.div>
          ))}
        </div>

      </div>
    </section>
  );
}
